/**
 * @summary Prenotazioni formattate per il calendario (per mese)
 */
export const getGetPrenotazioniCalendarioUrl = (
  params?: GetPrenotazioniCalendarioParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/dashboard/prenotazioni-calendario?${stringifiedParams}`
    : `/api/dashboard/prenotazioni-calendario`;
};

